mapper.select:
SELECT DISTINCT t.id, t.user_id AS userId, t.project_id AS projectId, t.parent_task_id AS parentTaskId, t.title, t.description, t.priority, t.status, t.tag, t.start_date AS startDate, t.due_date AS dueDate, t.is_note AS isNote, t.sort_order AS sortOrder, t.create_time AS createTime, t.update_time AS updateTime, CASE WHEN t.user_id = #{userId} THEN 'OWNER' WHEN COALESCE(sm.permission, sm_project.permission) = 'EDIT' THEN 'EDIT' WHEN COALESCE(sm.permission, sm_project.permission) = 'VIEW' THEN 'VIEW' ELSE 'VIEW' END AS accessLevel, CASE WHEN t.user_id = #{userId} THEN NULL ELSE (SELECT u.nickname FROM sys_user u WHERE u.id = t.user_id) END AS sharedByNickname, (SELECT COUNT(*) FROM share_member sm2 WHERE sm2.resource_type = 'TASK' AND sm2.resource_id = t.id) AS shareMemberCount, (SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END FROM share_link sl2 WHERE sl2.resource_type = 'TASK' AND sl2.resource_id = t.id AND sl2.is_active = 1) AS hasShareLink FROM task t LEFT JOIN share_member sm ON sm.resource_type = 'TASK' AND sm.resource_id = t.id AND sm.user_id = #{userId} LEFT JOIN share_member sm_project ON sm_project.resource_type = 'PROJECT' AND sm_project.resource_id = t.project_id AND sm_project.user_id = #{userId} WHERE ( t.user_id = #{userId} OR sm.user_id IS NOT NULL OR sm_project.user_id IS NOT NULL )
AND t.is_note = #{isNote}
AND t.project_id = #{projectId}
AND t.status = #{status}
AND t.priority = #{priority}
AND (t.title LIKE CONCAT('%', #{keyword}, '%') OR t.description LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY t.sort_order ASC, t.create_time DESC
